import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { SeedService } from '../../data/seed.service';
import { Forecast } from '../../data/models';

interface FamilyBar {
  family: string;
  value: number;
  pct: number;
}

@Component({
  selector: 'app-forecasting',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './forecasting.component.html',
  styleUrl: './forecasting.component.css',
})
export class ForecastingComponent {
  readonly scenarios: (Forecast['scenario'] | 'all')[] = ['all', 'committed', 'best-case'];
  scenarioFilter = signal<Forecast['scenario'] | 'all'>('all');

  totalValue = computed(() => this.seed.forecasts().reduce((s, f) => s + f.value, 0));
  committedValue = computed(() =>
    this.seed.forecasts().filter((f) => f.scenario === 'committed').reduce((s, f) => s + f.value, 0),
  );
  bestCaseValue = computed(() =>
    this.seed.forecasts().filter((f) => f.scenario === 'best-case').reduce((s, f) => s + f.value, 0),
  );
  weightedValue = computed(() =>
    Math.round(this.seed.forecasts().reduce((s, f) => s + (f.value * f.confidence) / 100, 0)),
  );

  filteredForecasts = computed(() => {
    const f = this.scenarioFilter();
    const rows = f === 'all'
      ? this.seed.forecasts()
      : this.seed.forecasts().filter((r) => r.scenario === f);
    return [...rows].sort((a, b) =>
      a.breakerFamily.localeCompare(b.breakerFamily) || b.value - a.value,
    );
  });

  familyBars = computed<FamilyBar[]>(() => {
    const order = ['E6.2', 'XT7', 'XT4', 'E4.2', 'XT6'];
    const map = new Map<string, number>();
    for (const f of this.seed.forecasts()) {
      map.set(f.breakerFamily, (map.get(f.breakerFamily) ?? 0) + f.value);
    }
    const rows = order
      .filter((fam) => map.has(fam))
      .map((fam) => ({ family: fam, value: map.get(fam) ?? 0, pct: 0 }));
    const max = Math.max(1, ...rows.map((r) => r.value));
    rows.forEach((r) => (r.pct = Math.round((r.value / max) * 100)));
    return rows;
  });

  setScenario(scenario: Forecast['scenario'] | 'all'): void {
    this.scenarioFilter.set(scenario);
  }

  scenarioBadge(scenario: Forecast['scenario']): string {
    switch (scenario) {
      case 'committed': return 'badge-success';
      case 'best-case': return 'badge-warning';
      default: return 'badge-neutral';
    }
  }

  constructor(public seed: SeedService) {}
}
